    95→// Copy returns a deep copy of the Histogram.
    96→func (h *Histogram) Copy() *Histogram {
    97→	c := Histogram{
    98→		CounterResetHint: h.CounterResetHint,
    99→		Schema:           h.Schema,
   100→		Count:            h.Count,
   101→		Sum:              h.Sum,
   102→	}
   103→
   104→	if h.UsesCustomBuckets() {
   105→		// Custom values are interned, it's ok to copy by reference.
   106→		c.CustomValues = h.CustomValues
   107→	} else {
   108→		c.ZeroThreshold = h.ZeroThreshold
   109→		c.ZeroCount = h.ZeroCount
   110→
   111→		if len(h.NegativeSpans) != 0 {
   112→			c.NegativeSpans = make([]Span, len(h.NegativeSpans))
   113→			copy(c.NegativeSpans, h.NegativeSpans)
   114→		}
   115→		if len(h.NegativeBuckets) != 0 {
   116→			c.NegativeBuckets = make([]int64, len(h.NegativeBuckets))
   117→			copy(c.NegativeBuckets, h.NegativeBuckets)
   118→		}
   119→	}
   120→
   121→	if len(h.PositiveSpans) != 0 {
   122→		c.PositiveSpans = make([]Span, len(h.PositiveSpans))
   123→		copy(c.PositiveSpans, h.PositiveSpans)
   124→	}
   125→	if len(h.PositiveBuckets) != 0 {
   126→		c.PositiveBuckets = make([]int64, len(h.PositiveBuckets))
   127→		copy(c.PositiveBuckets, h.PositiveBuckets)
   128→	}
   129→
   130→	return &c
   131→}
