   200→// ZeroBucket returns the zero bucket. This method panics if the schema is for custom buckets.
   201→func (h *Histogram) ZeroBucket() Bucket[uint64] {
   202→	if h.UsesCustomBuckets() {
   203→		panic("histograms with custom buckets have no zero bucket")
   204→	}
   205→	return Bucket[uint64]{
   206→		Lower:          -h.ZeroThreshold,
   207→		Upper:          h.ZeroThreshold,
   208→		LowerInclusive: true,
   209→		UpperInclusive: true,
   210→		Count:          h.ZeroCount,
   211→	}
   212→}
