   228→// CumulativeBucketIterator returns a BucketIterator to iterate over a
   229→// cumulative view of the buckets. This method currently only supports
   230→// Histograms without negative buckets and panics if the Histogram has negative
   231→// buckets. It is currently only used for testing.
   232→func (h *Histogram) CumulativeBucketIterator() BucketIterator[uint64] {
   233→	if len(h.NegativeBuckets) > 0 {
   234→		panic("CumulativeBucketIterator called on Histogram with negative buckets")
   235→	}
   236→	return &cumulativeBucketIterator{h: h, posSpansIdx: -1}
   237→}
