   239→// Equals returns true if the given histogram matches exactly.
   240→// Exact match is when there are no new buckets (even empty) and no missing buckets,
   241→// and all the bucket values match. Spans can have different empty length spans in between,
   242→// but they must represent the same bucket layout to match.
   243→// Sum is compared based on its bit pattern because this method
   244→// is about data equality rather than mathematical equality.
   245→// We ignore fields that are not used based on the exponential / custom buckets schema,
   246→// but check fields where differences may cause unintended behaviour even if they are not
   247→// supposed to be used according to the schema.
   248→func (h *Histogram) Equals(h2 *Histogram) bool {
   249→	if h2 == nil {
   250→		return h == nil
   251→	}
   252→
   253→	if h.Schema != h2.Schema || h.Count != h2.Count ||
   254→		math.Float64bits(h.Sum) != math.Float64bits(h2.Sum) {
   255→		return false
   256→	}
   257→
   258→	if h.UsesCustomBuckets() {
   259→		if !CustomBucketBoundsMatch(h.CustomValues, h2.CustomValues) {
   260→			return false
   261→		}
   262→	}
   263→
   264→	if h.ZeroThreshold != h2.ZeroThreshold || h.ZeroCount != h2.ZeroCount {
   265→		return false
   266→	}
   267→
   268→	if !spansMatch(h.NegativeSpans, h2.NegativeSpans) {
   269→		return false
   270→	}
   271→	if !slices.Equal(h.NegativeBuckets, h2.NegativeBuckets) {
   272→		return false
   273→	}
   274→
   275→	if !spansMatch(h.PositiveSpans, h2.PositiveSpans) {
   276→		return false
   277→	}
   278→	if !slices.Equal(h.PositiveBuckets, h2.PositiveBuckets) {
   279→		return false
   280→	}
   281→
   282→	return true
   283→}
