   285→// spansMatch returns true if both spans represent the same bucket layout
   286→// after combining zero length spans with the next non-zero length span.
   287→func spansMatch(s1, s2 []Span) bool {
   288→	if len(s1) == 0 && len(s2) == 0 {
   289→		return true
   290→	}
   291→
   292→	s1idx, s2idx := 0, 0
   293→	for {
   294→		if s1idx >= len(s1) {
   295→			return allEmptySpans(s2[s2idx:])
   296→		}
   297→		if s2idx >= len(s2) {
   298→			return allEmptySpans(s1[s1idx:])
   299→		}
   300→
   301→		currS1, currS2 := s1[s1idx], s2[s2idx]
   302→		s1idx++
   303→		s2idx++
   304→		if currS1.Length == 0 {
   305→			// This span is zero length, so we add consecutive such spans
   306→			// until we find a non-zero span.
   307→			for ; s1idx < len(s1) && s1[s1idx].Length == 0; s1idx++ {
   308→				currS1.Offset += s1[s1idx].Offset
   309→			}
   310→			if s1idx < len(s1) {
   311→				currS1.Offset += s1[s1idx].Offset
   312→				currS1.Length = s1[s1idx].Length
   313→				s1idx++
   314→			}
   315→		}
   316→		if currS2.Length == 0 {
   317→			// This span is zero length, so we add consecutive such spans
   318→			// until we find a non-zero span.
   319→			for ; s2idx < len(s2) && s2[s2idx].Length == 0; s2idx++ {
   320→				currS2.Offset += s2[s2idx].Offset
   321→			}
   322→			if s2idx < len(s2) {
   323→				currS2.Offset += s2[s2idx].Offset
   324→				currS2.Length = s2[s2idx].Length
   325→				s2idx++
   326→			}
   327→		}
   328→
   329→		if currS1.Length == 0 && currS2.Length == 0 {
   330→			// The last spans of both set are zero length. Previous spans match.
   331→			return true
   332→		}
   333→
   334→		if currS1.Offset != currS2.Offset || currS1.Length != currS2.Length {
   335→			return false
   336→		}
   337→	}
   338→}
