   349→// Compact works like FloatHistogram.Compact. See there for detailed
   350→// explanations.
   351→func (h *Histogram) Compact(maxEmptyBuckets int) *Histogram {
   352→	h.PositiveBuckets, _, h.PositiveSpans = compactBuckets(
   353→		h.PositiveBuckets, nil, h.PositiveSpans, maxEmptyBuckets, true,
   354→	)
   355→	h.NegativeBuckets, _, h.NegativeSpans = compactBuckets(
   356→		h.NegativeBuckets, nil, h.NegativeSpans, maxEmptyBuckets, true,
   357→	)
   358→	return h
   359→}
